interface Token {
  type: TokenType;
  value: string;
}

function tokenize(source: string): Token[] {
  const tokens: Token[] = [];
  let i = 0;
  while (i < source.length) {
    if (/\s/.test(source[i])) {
      i++;
      continue;
    }
    if (source[i] === "<") {
      tokens.push({ type: "LT", value: "<" });
      i++;
    } else if (source[i] === ">") {
      tokens.push({ type: "GT", value: ">" });
      i++;
    } else if (source[i] === "(") {
      tokens.push({ type: "LPAREN", value: "(" });
      i++;
    } else if (source[i] === ")") {
      tokens.push({ type: "RPAREN", value: ")" });
      i++;
    } else if (/[a-zA-Z_]\w*/.test(source[i])) {
      let ident = "";
      while (i < source.length && /\w/.test(source[i])) {
        ident += source[i];
        i++;
      }
      tokens.push({ type: "IDENT", value: ident });
    } else if (/[0-9]/.test(source[i])) {
      let num = "";
      while (i < source.length && /[0-9]/.test(source[i])) {
        num += source[i];
        i++;
      }
      tokens.push({ type: "NUMBER", value: num });
    } else {
      throw new Error(`Unexpected character '${source[i]}' at position ${i}`);
    }
  }
  return tokens;
}

